import { Routes, Route, Link } from "react-router-dom";
import Leaderboard from "./components/Leaderboard";
import PersonalGrowth from "./components/PersonalGrowth";

function App() {
  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h1>CPulse Tracker</h1>

      <nav style={{ marginBottom: "20px" }}>
        <Link to="/leaderboard" style={{ marginRight: "15px" }}>
          Leaderboard
        </Link>

        <Link to="/growth/john_doe/codeforces">
          Personal Growth
        </Link>
      </nav>

      <Routes>
        <Route path="/leaderboard" element={<Leaderboard />} />

        {/* username + platform come from URL params */}
        <Route
          path="/growth/:username/:platform"
          element={<PersonalGrowth />}
        />

        {/* default route */}
        <Route path="*" element={<div>Select a page</div>} />
      </Routes>
    </div>
  );
}

export default App;
